// src/ManageOfficers.js
import React from 'react';
import './manageOfficers.css'; // Ensure this CSS file is created for styling

const ManageOfficers = () => {
  const officers = [
    { id: 1, name: '', position: '', department: 'Sales', email: 'john@example.com' },
    { id: 2, name: 'Jane Smith', position: 'Coordinator', department: 'Marketing', email: 'jane@example.com' },
    { id: 3, name: 'Alice Johnson', position: 'Developer', department: 'IT', email: 'alice@example.com' },
    { id: 4, name: 'Bob Brown', position: 'Analyst', department: 'Finance', email: 'bob@example.com' },
    { id: 5, name: 'Charlie White', position: 'Intern', department: 'HR', email: 'charlie@example.com' },
  ];

  return (
    <div className="manage-officers">
      <h2>Manage Officers</h2>
      <table className="officer-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Position</th>
            <th>Department</th>
            <th>Email</th>
          </tr>
        </thead>
        <tbody>
          {officers.map(officer => (
            <tr key={officer.id}>
              <td>{officer.id}</td>
              <td>{officer.name}</td>
              <td>{officer.position}</td>
              <td>{officer.department}</td>
              <td>{officer.email}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ManageOfficers;
